const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema } = require('graphql');
const { Pool } = require('pg');

const pool = new Pool({
  user: 'yourUser',
  host: 'localhost',
  database: 'yourDatabase',
  password: 'yourPassword',
  port: 5432,
});

const schema = buildSchema(`
  type Author {
    id: ID!
    name: String!
  }

  type Post {
    id: ID!
    content: String!
    author: Author!
  }

  type Query {
    posts: [Post]
  }
`);

const root = {
  posts: async () => {
    const client = await pool.connect();
    try {
      const res = await client.query('SELECT * FROM posts');
      const posts = res.rows;

      for (let post of posts) {
        const authorRes = await client.query('SELECT * FROM authors WHERE id = $1', [post.author_id]);
        post.author = authorRes.rows[0];
      }

      return posts;
    } finally {
      client.release();
    }
  },
};

const app = express();
app.use('/graphql', graphqlHTTP({
  schema: schema,
  rootValue: root,
  graphiql: true,
}));

app.listen(4000, () => console.log('Server is running on http://localhost:4000/graphql'));